// Gateway mode pricing multipliers (applied to base provider token costs)
// Higher plans get lower rates — economies of scale
export const GATEWAY_MULTIPLIERS = {
  starter:    { pooled: 1.5, dedicated: 2.0 },
  pro:        { pooled: 1.3, dedicated: 1.7 },
  enterprise: { pooled: 1.1, dedicated: 1.4 },
} as const;

// Backwards-compat defaults (starter tier)
export const POOLED_MARKUP = GATEWAY_MULTIPLIERS.starter.pooled;
export const DEDICATED_MARKUP = GATEWAY_MULTIPLIERS.starter.dedicated;

export type GatewayPlanTier = keyof typeof GATEWAY_MULTIPLIERS;

export function getGatewayMultiplier(plan: string, mode: "pooled" | "dedicated"): number {
  const tier = plan in GATEWAY_MULTIPLIERS ? (plan as GatewayPlanTier) : "starter";
  return GATEWAY_MULTIPLIERS[tier][mode];
}

